function showRedirectionAnimation(e,t=""){const n=document.getElementById("redirectionOverlay"),i=document.getElementById("countdown"),o=document.querySelector(".spinner-text");n.classList.add("active");let c=3;i.textContent=c;const r=["Préparation...","Connexion...","Redirection..."];let a=0;const d=setInterval(()=>{c--,i.textContent=c,a<r.length-1&&(a++,o.textContent=r[a]),c<=0&&(clearInterval(d),n.classList.remove("active"),window.open(e,"_blank"))},1e3)}function attachRedirectionListeners(){document.querySelectorAll(".reserve-btn").forEach(e=>{e.removeEventListener("click",handleReserveClick),e.addEventListener("click",handleReserveClick)})}function handleReserveClick(e){e.preventDefault();showRedirectionAnimation(this.getAttribute("data-url"))}document.addEventListener("DOMContentLoaded",function(){attachRedirectionListeners()}),window.attachRedirectionListeners=attachRedirectionListeners,document.getElementById("redirectionOverlay").addEventListener("click",function(e){e.target===this&&(this.style.display="none")});